import{_ as i,o as l,c as e,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"象理用","description":"象理用适合拿来整理跨文本阅读，让理解不只停在“看到象”，也不悬在“空谈理”。","frontmatter":{"title":"象理用","description":"象理用适合拿来整理跨文本阅读，让理解不只停在“看到象”，也不悬在“空谈理”。","category":"guide","aliases":["象理用","象理用专题","象理用"]},"headers":[],"relativePath":"topics/xiang-li-yong.md","filePath":"topics/xiang-li-yong.md","lastUpdated":1777132262000}'),o={name:"topics/xiang-li-yong.md"};function r(n,a,s,h,d,c){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="象理用" tabindex="-1">象理用 <a class="header-anchor" href="#象理用" aria-label="Permalink to &quot;象理用&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>象理用可以作为今天读经时的一条整理线：</p><ul><li>先看象：看结构、形态、关系、表象</li><li>再通理：看这些象背后说明了什么原则</li><li>最后落用：看这些原则今天怎样帮助理解现实</li></ul><p>这条线之所以重要，是因为它能把“看懂一点”和“真正会用”连起来。</p><h2 id="为什么重要" tabindex="-1">为什么重要 <a class="header-anchor" href="#为什么重要" aria-label="Permalink to &quot;为什么重要&quot;">​</a></h2><p>很多阅读停在两个极端：</p><ul><li>只看象，最后只剩符号印象</li><li>只谈理，最后离开原文与现实</li></ul><p>象理用的价值，就是帮人把这三层重新接起来，让阅读不散。</p><h2 id="怎么读-怎么进入" tabindex="-1">怎么读 / 怎么进入 <a class="header-anchor" href="#怎么读-怎么进入" aria-label="Permalink to &quot;怎么读 / 怎么进入&quot;">​</a></h2><p>可以先拿一个熟悉的小例子练手：</p><ol><li>先问：我看到了什么象？</li><li>再问：这个象背后说明了什么关系或原则？</li><li>最后问：这种关系今天还能怎样帮助我理解问题？</li></ol><p>这样读，不需要一开始就很高深，但会越来越稳。</p><h2 id="相关原典" tabindex="-1">相关原典 <a class="header-anchor" href="#相关原典" aria-label="Permalink to &quot;相关原典&quot;">​</a></h2><ul><li>《周易》</li><li>《象传》</li><li>《系辞上传》</li><li>《庄子》</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：这里先留给后续把自己“从象到理再到用”的阅读样例补进来。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li><a href="/Dao/yijing/basics/concepts/xiang-li-yong">易经概念：象理用</a></li></ul>',19)])])}const _=i(o,[["render",r]]);export{u as __pageData,_ as default};
